changeSet.sql:
WITH doc_cat AS (
    SELECT id FROM category WHERE entity_name = 'document'
),
sc_fin AS (
    SELECT id FROM sub_category WHERE name = 'Finanzen & Versicherungen' AND category_id = (SELECT id FROM doc_cat)
),
scg_invoice AS (
    SELECT id FROM sub_category_group WHERE name = 'Rechnungen' AND sub_category_id = (SELECT id FROM sc_fin)
)
INSERT INTO group_type (id, name, translation_key, sub_category_group_id)
SELECT nextval('sequence_generator'), 'Eingangsrechnung', 'jaynaApp.document.type.purchase-invoice', (SELECT id FROM scg_invoice)
WHERE EXISTS (SELECT 1 FROM scg_invoice)
  AND NOT EXISTS (SELECT 1 FROM group_type WHERE name = 'Eingangsrechnung' AND sub_category_group_id = (SELECT id FROM scg_invoice));
